// Sélectionner ou créer la liste
const liste = document.createElement('ul');
document.body.appendChild(liste);

const langages = ['HTML', 'CSS', 'JavaScript'];
langages.forEach(lang => {
  const li = document.createElement('li');
  li.textContent = lang;
  liste.appendChild(li);
});

const inputTache = document.getElementById('nouvelleTache');
const btnAjouterFin = document.getElementById('ajouterFin');
const liste = document.getElementById('listeTaches');

btnAjouterFin.addEventListener('click', () => {
  const nouvelleTache = document.createElement('li');
  nouvelleTache.textContent = inputTache.value;
  const btnSuppr = document.createElement('button');
  btnSuppr.textContent = 'Supprimer';
  btnSuppr.onclick = () => nouvelleTache.remove();
  nouvelleTache.appendChild(btnSuppr);
  liste.appendChild(nouvelleTache);
  inputTache.value = '';
});

const btnInsertDebut = document.getElementById('insererDebut');

btnInsertDebut.addEventListener('click', () => {
  const nouvelleTache = document.createElement('li');
  nouvelleTache.textContent = inputTache.value;
  const btnSuppr = document.createElement('button');
  btnSuppr.textContent = 'Supprimer';
  btnSuppr.onclick = () => nouvelleTache.remove();
  nouvelleTache.appendChild(btnSuppr);

  const premiereTache = liste.firstElementChild;
  if (premiereTache) {
    liste.insertBefore(nouvelleTache, premiereTache);
  } else {
    liste.appendChild(nouvelleTache);
  }
  inputTache.value = '';
});
